import Foundation
import TuistCore
import TuistLogging
import TuistSupport
import XcodeGraph

/// A target mapper that enforces explicit dependencies by adding custom build directories
public struct ExplicitDependencyGraphMapper: GraphMapping {
    public init() {}

    public func map(
        graph: Graph,
        environment: MapperEnvironment
    ) async throws -> (Graph, [SideEffectDescriptor], MapperEnvironment) {
        if !graph.packages.isEmpty {
            return (
                graph,
                [],
                environment
            )
        }
        Logger.current.debug("Transforming graph \(graph.name): Enforcing explicit dependencies")

        let graphTraverser = GraphTraverser(graph: graph)

        var graph = graph

        graph.projects = Dictionary(uniqueKeysWithValues: graph.projects.map { projectPath, project in
            var project = project
            project.targets = project.targets.mapValues { target in
                let graphTarget = GraphTarget(path: projectPath, target: target, project: project)
                let projectDebugConfigurations = project.settings.configurations.keys
                    .filter { $0.variant == .debug }
                    .map(\.name)

                let mappedTarget = map(
                    graphTarget,
                    graphTraverser: graphTraverser,
                    debugConfigurations: projectDebugConfigurations
                        .isEmpty ? [project.defaultDebugBuildConfigurationName] : projectDebugConfigurations
                )

                return mappedTarget
            }

            return (projectPath, project)
        })
        return (graph, [], environment)
    }

    // swiftlint:disable:next function_body_length
    private func map(_ graphTarget: GraphTarget, graphTraverser: GraphTraversing, debugConfigurations: [String]) -> Target {
        let allTargetDependencies = graphTraverser.allTargetDependencies(
            path: graphTarget.path,
            name: graphTarget.target.name
        )
        let frameworkSearchPaths = allTargetDependencies
            .sorted()
            .map(\.target.productName).map {
                "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/\($0)"
            }

        switch graphTarget.target.product {
        case .dynamicLibrary, .staticLibrary, .framework, .staticFramework, .bundle:
            break
        default:
            return graphTarget.target
        }

        var additionalSettings: SettingsDictionary = [
            "TARGET_BUILD_DIR": "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)",
            "BUILT_PRODUCTS_DIR": "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)",
        ]

        if case .external = graphTarget.project.type {
            additionalSettings["FRAMEWORK_SEARCH_PATHS"] = .array(["$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)"])
        } else if !frameworkSearchPaths.isEmpty {
            additionalSettings["FRAMEWORK_SEARCH_PATHS"] = .array(frameworkSearchPaths)
        }

        // If any dependency of this target has "ENABLE_TESTING_SEARCH_PATHS" set to "YES", it needs to be propagated
        // on the upstream target as well
        if graphTraverser.needsEnableTestingSearchPaths(path: graphTarget.path, name: graphTarget.target.name) {
            additionalSettings["ENABLE_TESTING_SEARCH_PATHS"] = .string("YES")
        }

        var target = graphTarget.target
        target.settings = Settings(
            base: target.settings?.base ?? [:],
            baseDebug: additionalSettings,
            configurations: target.settings?.configurations ?? [:]
        )

        let copyBuiltProductsScript: String
        let builtProductsScriptInputPaths: [String]
        let builtProductsScriptOutputPaths: [String]

        switch target.product {
        case .staticLibrary:
            let (libScript, libInputPaths, libOutputPaths) = copyBuiltProductsToSharedDirectory(
                debugConfigurations: debugConfigurations,
                extensionName: "a",
                prefix: "lib"
            )
            let (moduleScript, moduleInputPaths, moduleOutputPaths) = copyBuiltProductsToSharedDirectory(
                debugConfigurations: debugConfigurations,
                extensionName: "swiftmodule"
            )
            copyBuiltProductsScript = [libScript, moduleScript].joined(separator: "\n")

            builtProductsScriptInputPaths = libInputPaths + moduleInputPaths
            builtProductsScriptOutputPaths = libOutputPaths + moduleOutputPaths
        case .dynamicLibrary:
            (
                copyBuiltProductsScript,
                builtProductsScriptInputPaths,
                builtProductsScriptOutputPaths
            ) = copyBuiltProductsToSharedDirectory(
                debugConfigurations: debugConfigurations,
                extensionName: "swiftmodule"
            )
        case .bundle:
            (
                copyBuiltProductsScript,
                builtProductsScriptInputPaths,
                builtProductsScriptOutputPaths
            ) = copyBuiltProductsToSharedDirectory(
                debugConfigurations: debugConfigurations,
                extensionName: "bundle"
            )
        case .framework, .staticFramework:
            (
                copyBuiltProductsScript,
                builtProductsScriptInputPaths,
                builtProductsScriptOutputPaths
            ) = copyBuiltProductsToSharedDirectory(
                debugConfigurations: debugConfigurations,
                extensionName: "framework"
            )
        default:
            return graphTarget.target
        }

        target = target.with(
            scripts: target.scripts + [
                TargetScript(
                    name: "Copy Built Products for Explicit Dependencies",
                    order: .post,
                    script: .embedded(
                        """
                        # This script copies built products into the shared directory to be available for app and other targets that don't have scoped directories
                        # If you try to archive any of the configurations seen in the output paths, the operation will fail due to `Multiple commands produce` error

                        \(copyBuiltProductsScript)
                        """
                    ),
                    inputPaths: builtProductsScriptInputPaths,
                    outputPaths: builtProductsScriptOutputPaths
                ),
            ]
        )
        return target
    }

    private func copyBuiltProductsToSharedDirectory(
        debugConfigurations: [String],
        extensionName: String,
        prefix: String = ""
    ) -> (String, [String], [String]) { // swiftlint:disable:this large_tuple
        let script = debugConfigurations.map {
            copyScript(for: $0, extensionName: extensionName, prefix: prefix)
        }
        .joined(separator: "\n")

        return (
            script,
            debugConfigurations.map {
                "$(BUILD_DIR)/\($0)$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)/\(prefix)$(PRODUCT_NAME).\(extensionName)"
            },
            debugConfigurations.map {
                "$(BUILD_DIR)/\($0)$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/\(prefix)$(PRODUCT_NAME).\(extensionName)"
            }
        )
    }

    private func copyScript(
        for configuration: String,
        extensionName: String,
        prefix: String
    ) -> String {
        """
        FILE="$BUILD_DIR/\(configuration)$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME/\(prefix)$PRODUCT_NAME.\(
            extensionName
        )"
        DESTINATION_FILE="$BUILD_DIR/\(configuration)$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/\(prefix)$PRODUCT_NAME.\(
            extensionName
        )"
        if [[ -d "$FILE" && ! -d "$DESTINATION_FILE" ]]; then
            ln -s "$FILE" "$DESTINATION_FILE"
        fi

        if [[ -f "$FILE" && ! -f "$DESTINATION_FILE" ]]; then
            ln -s "$FILE" "$DESTINATION_FILE"
        fi
        """
    }
}

import Foundation
import TuistCore
import TuistSupport
import TuistTesting
import XcodeGraph
import XCTest
@testable import TuistGenerator

final class ExplicitDependencyGraphMapperTests: TuistUnitTestCase {
    private var subject: ExplicitDependencyGraphMapper!

    override func setUp() {
        super.setUp()
        subject = ExplicitDependencyGraphMapper()
    }

    override func tearDown() {
        subject = nil
        super.tearDown()
    }

    func test_map() async throws {
        // Given
        let projectAPath = fileHandler.currentPath.appending(component: "ProjectA")
        let externalProjectBPath = fileHandler.currentPath.appending(component: "ProjectB")
        let frameworkA: Target = .test(
            name: "FrameworkA",
            product: .framework,
            dependencies: [
                .target(name: "DynamicLibraryB"),
                .project(target: "ExternalFrameworkC", path: externalProjectBPath),
            ]
        )
        let dynamicLibraryB: Target = .test(
            name: "DynamicLibraryB",
            product: .dynamicLibrary,
            productName: "DynamicLibraryB",
            settings: .test(
                configurations: [
                    .debug: .test(),
                    .release: .test(),
                ]
            )
        )
        let externalFrameworkC: Target = .test(
            name: "ExternalFrameworkC",
            product: .staticFramework,
            productName: "ExternalFrameworkC"
        )
        let graph = Graph.test(
            projects: [
                projectAPath: .test(
                    targets: [
                        .test(
                            name: "App",
                            product: .app,
                            dependencies: [
                                .target(name: "FrameworkA"),
                            ]
                        ),
                        frameworkA,
                        dynamicLibraryB,
                    ]
                ),
                externalProjectBPath: .test(
                    targets: [
                        externalFrameworkC,
                    ],
                    type: .external(hash: nil)
                ),
            ],
            dependencies: [
                .target(name: "FrameworkA", path: projectAPath): [
                    .target(name: "DynamicLibraryB", path: projectAPath),
                    .target(name: "ExternalFrameworkC", path: externalProjectBPath),
                ],
            ]
        )

        // When
        let got = try await subject.map(graph: graph, environment: MapperEnvironment())
        let copyScript = """
        if [[ -d "$FILE" && ! -d "$DESTINATION_FILE" ]]; then
            ln -s "$FILE" "$DESTINATION_FILE"
        fi

        if [[ -f "$FILE" && ! -f "$DESTINATION_FILE" ]]; then
            ln -s "$FILE" "$DESTINATION_FILE"
        fi
        """

        // Then
        let gotAProject = try XCTUnwrap(got.0.projects[projectAPath])
        let gotATargets = Array(gotAProject.targets.values).sorted()
        XCTAssertEqual(
            gotATargets[0],
            .test(
                name: "App",
                product: .app,
                dependencies: [
                    .target(name: "FrameworkA"),
                ]
            )
        )
        let gotFrameworkA = try XCTUnwrap(gotATargets[2])
        XCTAssertEqual(
            gotFrameworkA.name,
            "FrameworkA"
        )
        XCTAssertEqual(
            gotFrameworkA.product,
            .framework
        )
        XCTAssertEqual(
            gotFrameworkA.settings?.baseDebug["BUILT_PRODUCTS_DIR"],
            "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)"
        )
        XCTAssertEqual(
            gotFrameworkA.settings?.baseDebug["TARGET_BUILD_DIR"],
            "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)"
        )
        switch gotFrameworkA.settings?.baseDebug["FRAMEWORK_SEARCH_PATHS"] {
        case let .array(array):
            XCTAssertEqual(
                Set(array),
                Set(
                    [
                        "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/DynamicLibraryB",
                        "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/ExternalFrameworkC",
                    ]
                )
            )
        default:
            XCTFail("Invalid case for FRAMEWORK_SEARCH_PATHS")
        }
        XCTAssertEqual(
            gotFrameworkA.scripts,
            [
                TargetScript(
                    name: "Copy Built Products for Explicit Dependencies",
                    order: .post,
                    script: .embedded("""
                    # This script copies built products into the shared directory to be available for app and other targets that don't have scoped directories
                    # If you try to archive any of the configurations seen in the output paths, the operation will fail due to `Multiple commands produce` error

                    FILE="$BUILD_DIR/Debug$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME/$PRODUCT_NAME.framework"
                    DESTINATION_FILE="$BUILD_DIR/Debug$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME.framework"
                    \(copyScript)
                    """),
                    inputPaths: [
                        "$(BUILD_DIR)/Debug$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)/$(PRODUCT_NAME).framework",
                    ],
                    outputPaths: [
                        "$(BUILD_DIR)/Debug$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME).framework",
                    ]
                ),
            ]
        )
        XCTAssertEqual(
            gotFrameworkA.dependencies,
            [
                .target(name: "DynamicLibraryB"),
                .project(target: "ExternalFrameworkC", path: externalProjectBPath),
            ]
        )

        XCTAssertEqual(
            gotATargets[1],
            .test(
                name: "DynamicLibraryB",
                product: .dynamicLibrary,
                settings: .test(
                    baseDebug: [
                        "BUILT_PRODUCTS_DIR": "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)",
                        "TARGET_BUILD_DIR": "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)",
                    ],
                    configurations: [
                        .debug: .test(),
                        .release: .test(),
                    ]
                ),
                scripts: [
                    TargetScript(
                        name: "Copy Built Products for Explicit Dependencies",
                        order: .post,
                        script: .embedded("""
                        # This script copies built products into the shared directory to be available for app and other targets that don't have scoped directories
                        # If you try to archive any of the configurations seen in the output paths, the operation will fail due to `Multiple commands produce` error

                        FILE="$BUILD_DIR/Debug$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME/$PRODUCT_NAME.swiftmodule"
                        DESTINATION_FILE="$BUILD_DIR/Debug$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME.swiftmodule"
                        \(copyScript)
                        """),
                        inputPaths: [
                            "$(BUILD_DIR)/Debug$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)/$(PRODUCT_NAME).swiftmodule",
                        ],
                        outputPaths: [
                            "$(BUILD_DIR)/Debug$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME).swiftmodule",
                        ]
                    ),
                ]
            )
        )
        let gotExternalBProject = try XCTUnwrap(got.0.projects[externalProjectBPath])
        let gotExternalBTargets = Array(gotExternalBProject.targets.values)
        XCTAssertEqual(
            gotExternalBTargets,
            [
                .test(
                    name: "ExternalFrameworkC",
                    product: .staticFramework,
                    productName: "ExternalFrameworkC",
                    settings: .test(
                        baseDebug: [
                            "BUILT_PRODUCTS_DIR": "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)",
                            "TARGET_BUILD_DIR": "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)",
                            "FRAMEWORK_SEARCH_PATHS": [
                                "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)",
                            ],
                        ]
                    ),
                    scripts: [
                        TargetScript(
                            name: "Copy Built Products for Explicit Dependencies",
                            order: .post,
                            script: .embedded("""
                            # This script copies built products into the shared directory to be available for app and other targets that don't have scoped directories
                            # If you try to archive any of the configurations seen in the output paths, the operation will fail due to `Multiple commands produce` error

                            FILE="$BUILD_DIR/Debug$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME/$PRODUCT_NAME.framework"
                            DESTINATION_FILE="$BUILD_DIR/Debug$EFFECTIVE_PLATFORM_NAME$TARGET_BUILD_SUBPATH/$PRODUCT_NAME.framework"
                            \(copyScript)
                            """),
                            inputPaths: [
                                "$(BUILD_DIR)/Debug$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME)/$(PRODUCT_NAME).framework",
                            ],
                            outputPaths: [
                                "$(BUILD_DIR)/Debug$(EFFECTIVE_PLATFORM_NAME)$(TARGET_BUILD_SUBPATH)/$(PRODUCT_NAME).framework",
                            ]
                        ),
                    ]
                ),
            ]
        )
    }

    func test_enabling_testing_search_paths() async throws {
        // Given
        let projectAPath = fileHandler.currentPath.appending(component: "ProjectA")
        let externalProjectBPath = fileHandler.currentPath.appending(component: "ProjectB")

        let frameworkA: Target = .test(
            name: "FrameworkA",
            product: .framework,
            dependencies: [
                .project(target: "ExternalFrameworkB", path: externalProjectBPath),
            ]
        )

        let externalFrameworkB: Target = .test(
            name: "ExternalFrameworkB",
            product: .staticFramework,
            productName: "ExternalFrameworkB",
            settings: .test(base: ["ENABLE_TESTING_SEARCH_PATHS": .string("YES")])
        )

        let graph = Graph.test(
            projects: [
                projectAPath: .test(
                    targets: [
                        frameworkA,
                    ]
                ),
                externalProjectBPath: .test(
                    targets: [
                        externalFrameworkB,
                    ],
                    type: .external(hash: nil)
                ),
            ],
            dependencies: [
                .target(name: "FrameworkA", path: projectAPath): [
                    .target(name: "ExternalFrameworkB", path: externalProjectBPath),
                ],
            ]
        )

        // When
        let got = try await subject.map(graph: graph, environment: MapperEnvironment())

        // Then
        let gotAProject = try XCTUnwrap(got.0.projects[projectAPath])
        let gotATargets = Array(gotAProject.targets.values).sorted()
        let gotFrameworkA = try XCTUnwrap(gotATargets[0])
        XCTAssertEqual(
            gotFrameworkA.name,
            "FrameworkA"
        )
        XCTAssertEqual(
            gotFrameworkA.product,
            .framework
        )

        // ENABLE_TESTING_SEARCH_PATHS is propagated from ExternalFrameworkB
        XCTAssertEqual(
            gotFrameworkA.settings?.baseDebug["ENABLE_TESTING_SEARCH_PATHS"],
            .string("YES")
        )
    }
}

