    func test_map_app_gets_search_paths_through_dynamic_framework() async throws {
        // Given: App -> DynamicFramework -> StaticSPMPackage
        let projectPath = fileHandler.currentPath.appending(component: "Project")
        let externalProjectPath = fileHandler.currentPath.appending(component: "ExternalProject")

        let app: Target = .test(
            name: "App",
            product: .app,
            dependencies: [
                .target(name: "DynamicFramework"),
            ]
        )
        let dynamicFramework: Target = .test(
            name: "DynamicFramework",
            product: .framework,
            dependencies: [
                .project(target: "StaticSPMPackage", path: externalProjectPath),
            ]
        )
        let staticSPMPackage: Target = .test(
            name: "StaticSPMPackage",
            product: .staticFramework,
            productName: "StaticSPMPackage"
        )

        let graph = Graph.test(
            projects: [
                projectPath: .test(
                    targets: [
                        app,
                        dynamicFramework,
                    ]
                ),
                externalProjectPath: .test(
                    targets: [
                        staticSPMPackage,
                    ],
                    type: .external(hash: nil)
                ),
            ],
            dependencies: [
                .target(name: "App", path: projectPath): [
                    .target(name: "DynamicFramework", path: projectPath),
                ],
                .target(name: "DynamicFramework", path: projectPath): [
                    .target(name: "StaticSPMPackage", path: externalProjectPath),
                ],
            ]
        )

        // When
        let got = try await subject.map(graph: graph, environment: MapperEnvironment())

        // Then
        let gotProject = try XCTUnwrap(got.0.projects[projectPath])
        let gotTargets = Array(gotProject.targets.values).sorted()

        let gotApp = try XCTUnwrap(gotTargets.first(where: { $0.name == "App" }))
        switch gotApp.settings?.baseDebug["FRAMEWORK_SEARCH_PATHS"] {
        case let .array(array):
            XCTAssertEqual(
                Set(array),
                Set([
                    "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/DynamicFramework",
                    "$(CONFIGURATION_BUILD_DIR)$(TARGET_BUILD_SUBPATH)/StaticSPMPackage",
                ])
            )
        default:
            XCTFail("App target should have FRAMEWORK_SEARCH_PATHS for transitive dependencies behind dynamic framework")
        }
    }

    func test_enabling_testing_search_paths() async throws {
        // Given
        let projectAPath = fileHandler.currentPath.appending(component: "ProjectA")
        let externalProjectBPath = fileHandler.currentPath.appending(component: "ProjectB")

        let frameworkA: Target = .test(
            name: "FrameworkA",
            product: .framework,
            dependencies: [
                .project(target: "ExternalFrameworkB", path: externalProjectBPath),
            ]
        )

        let externalFrameworkB: Target = .test(
            name: "ExternalFrameworkB",
            product: .staticFramework,
            productName: "ExternalFrameworkB",
            settings: .test(base: ["ENABLE_TESTING_SEARCH_PATHS": .string("YES")])
        )

        let graph = Graph.test(
            projects: [
                projectAPath: .test(
                    targets: [
                        frameworkA,
                    ]
                ),
                externalProjectBPath: .test(
                    targets: [
                        externalFrameworkB,
                    ],
                    type: .external(hash: nil)
                ),
            ],
            dependencies: [
                .target(name: "FrameworkA", path: projectAPath): [
                    .target(name: "ExternalFrameworkB", path: externalProjectBPath),
                ],
            ]
        )

        // When
        let got = try await subject.map(graph: graph, environment: MapperEnvironment())

        // Then
        let gotAProject = try XCTUnwrap(got.0.projects[projectAPath])
        let gotATargets = Array(gotAProject.targets.values).sorted()
        let gotFrameworkA = try XCTUnwrap(gotATargets[0])
