var moduleMapPath: AbsolutePath? {
    switch self {
    case let .custom(path, umbrellaHeaderPath: _):
        return path
    case let .header(_, moduleMapPath: path):
        return path
    case let .directory(moduleMapPath: path, umbrellaDirectory: _):
        return path
    case .none:
        return nil
    }
}

