 68→    private func merge(oldValue: SettingValue?, newValue: SettingValue, inherit: Bool) -> SettingValue {
 69→        // No need to merge, just return newValue when the oldValue is nil (buildSettings[key] == nil).
 70→        guard let oldValue else {
 71→            return newValue
 72→        }
 73→
 74→        // No need to merge, just return oldValue when the newValue is exactly the same.
 75→        guard oldValue != newValue else {
 76→            return oldValue
 77→        }
 78→
 79→        // Both the oldValue and newValue are not nil. If the newValue contains $(inherited),
 80→        // it will need to be merged with the oldValue, otherwise the oldValue will be discarded
 81→        // and the newValue returned without merging.
 82→        //
 83→        // The .sortAndTrim() method ensures the result of merging does not contain duplicate "$(inherited)" and that
 84→        // "$(inherited)" is the first element
 85→        // i.e. merging the following values:
 86→        // oldValue = ["$(inherited)", "VALUE_1"]
 87→        // newValue = ["$(inherited)", "VALUE_2"]
 88→        // would result in ["$(inherited)", "$(inherited)", "VALUE_1", "VALUE_2"] if .sortAndTrim() was not used.
 89→        let inherited = "$(inherited)"
 90→        switch (oldValue, newValue) {
 91→        case let (.string(old), .string(new)) where new.contains(inherited) || inherit:
 92→            // Example: ("OLD", "$(inherited) NEW") -> ["$(inherited) NEW", "OLD"]
 93→            // This case shouldn't happen as all default multi-value settings are defined as NSArray<NSString>
 94→            return .array(Self.sortAndTrim(array: [old, new], element: inherited))
 95→
 96→        case let (.string(old), .array(new)) where new.contains(inherited) || inherit:
 97→            // Example: ("OLD", ["$(inherited)", "NEW"]) -> ["$(inherited)", "NEW", "OLD"]
 98→            return .array(Self.sortAndTrim(array: [old] + new, element: inherited))
 99→
100→        case let (.array(old), .string(new)) where new.contains(inherited) || inherit:
101→            // Example: (["OLD", "OLD_2"], "$(inherited) NEW") -> ["$(inherited) NEW", "OLD", "OLD_2"]
102→            // This case shouldn't happen as all default multi-value settings are defined as NSArray<NSString>
103→            return .array(Self.sortAndTrim(array: old + [new], element: inherited))
104→
105→        case let (.array(old), .array(new)) where new.contains(inherited) || inherit:
106→            // Example: (["OLD", "OLD_2"], ["$(inherited)", "NEW"]) -> ["$(inherited)", "NEW", "OLD", OLD_2"]
107→            return .array(Self.sortAndTrim(array: old + new, element: inherited))
108→
109→        default:
110→            // The newValue does not contain $(inherited) so the oldValue should be omitted
111→            return newValue
112→        }
113→    }
114→
115→    private static func sortAndTrim(array: [String], element: String) -> [String] {
116→        guard array.contains(where: { $0.starts(with: element) }) else { return array }
117→        // Move items that contain `element` to the top of the array
118→        return array
119→            .sorted { first, _ in first.contains(element) }
120→            .enumerated()
121→            .compactMap { index, item in
122→                // Remove duplicate `element`
123→                if index > 0,
124→                   item == element
125→                {
126→                    return nil
127→                } else if index > 0, item.contains(element) {
128→                    // "$(inherited) flag" -> "flag"
129→                    return item
130→                        .replacingOccurrences(of: element, with: "")
131→                        .trimmingCharacters(in: .whitespacesAndNewlines)
132→                } else {
133→                    return item
134→                }
135→            }
136→    }
137→}
